arguments.command:
curl -X POST "https://discord.com/api/v10/channels/1470276736066519164/messages" \
  -H "Authorization: Bot ${DISCORD_BOT_TOKEN}" \
  -H "Content-Type: application/json" \
  -d '{
    "content": "⏰ **9 AM Reminder**\n\n<@ianjames> Hey, time to ask on this channel: **Ano ang needed na baklon before magpuli?**\n\nDon'\''t forget to check what needs to be bought before heading home!"
  }' 2>&1 || echo "Note: DISCORD_BOT_TOKEN may not be set or curl may fail"
